text:
    return jsonify({"error": msg_text, "plan": plan}), 403

content_length = request.content_length
if content_length and content_length > _MAX_AUDIO_TRANSCRIPTION_BYTES:
    return jsonify({"error": "Audio file too large."}), 413

audio_file = request.files.get("file") or request.files.get("audio")
if not audio_file:
    return jsonify({"error": "Missing audio file."}), 400

filename = os.path.basename(audio_file.filename or "") or "audio.webm"
mimetype = audio_file.mimetype or "application/octet-stream"

try:
    payload = audio_file.read()
except Exception:
    logger.exception("[AudioTranscribe] Failed to read uploaded audio.")
    return jsonify({"error": "Unable to read audio file."}), 400

if not payload:
    return jsonify({"error": "Empty audio file."}), 400

if len(payload) > _MAX_AUDIO_TRANSCRIPTION_BYTES:
    return jsonify({"error": "Audio file too large."}), 413

client = get_openai_client()
if not client:
    return jsonify({"error": "OpenAI client is not configured."}), 500

try:
    result = client.audio.transcriptions.create(
        model="gpt-4o-mini-transcribe",
        file=(filename, payload, mimetype),
    )
except Exception:
    logger.exception("[AudioTranscribe] Transcription request failed.")
    return jsonify({"error": "Transcription failed."}), 500

text = (getattr(result, "text", None) or "").strip()
if not text:
    return jsonify({"error": "Transcription returned no text."}), 500

return jsonify({"text": text})
